import{_ as o,o as a,c as s,ag as n,ah as r}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"任务与工作区","description":"","frontmatter":{},"headers":[],"relativePath":"features/tasks-and-workspaces.md","filePath":"features/tasks-and-workspaces.md"}'),e={name:"features/tasks-and-workspaces.md"};function l(d,t,i,g,h,c){return a(),s("div",null,[...t[0]||(t[0]=[n('<h1 id="任务与工作区" tabindex="-1">任务与工作区 <a class="header-anchor" href="#任务与工作区" aria-label="Permalink to &quot;任务与工作区&quot;">​</a></h1><p>LoongCode 用<strong>工作区</strong>（Workspace，对应你磁盘上的项目目录）和<strong>任务</strong>（Task，对应一次 AI 对话会话）两级结构来组织你的工作。本页介绍如何添加工作区、管理任务生命周期，以及置顶、搜索、归档等高效操作。</p><blockquote><p>如果你还没开始第一个任务，建议先看<a href="/docs/guide/quick-start.html">快速上手</a>了解基础操作流程。</p></blockquote><p><img src="'+r+'" alt="截图：左侧任务栏展开状态，从上到下显示搜索框、＋ 打开工作区、＋ 新建任务、置顶组与任务列表，突出整体层级关系"></p><hr><h2 id="左侧任务栏布局" tabindex="-1">左侧任务栏布局 <a class="header-anchor" href="#左侧任务栏布局" aria-label="Permalink to &quot;左侧任务栏布局&quot;">​</a></h2><p>左侧任务栏从上到下的真实元素顺序为：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>Logo / 折叠按钮</strong></td><td>悬浮后可折叠侧栏（v0.7.0 起）</td></tr><tr><td><strong>搜索框</strong></td><td>按关键词实时筛选任务</td></tr><tr><td><strong>＋ 打开工作区</strong></td><td>添加项目文件夹为工作区</td></tr><tr><td><strong>＋ 新建任务</strong></td><td>快速新建一个任务草稿</td></tr><tr><td><strong>已置顶</strong></td><td>已置顶任务集合，独立于分组折叠</td></tr><tr><td><strong>任务大组头</strong></td><td>含「任务 / 归档」标签与视图切换（分组列表 / 时间线）</td></tr><tr><td><strong>工作区树 + 任务列表</strong></td><td>按工作区分组，展示各任务</td></tr><tr><td><strong>底部栏</strong></td><td>新手引导、移动端支持、打开设置</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">快捷键</p><ul><li><code>Ctrl+N</code>：新建任务草稿（任意界面可用）</li><li>悬浮 Logo 点击：折叠 / 展开左侧任务栏（v0.7.0）</li></ul></div><hr><h2 id="添加与管理工作区" tabindex="-1">添加与管理工作区 <a class="header-anchor" href="#添加与管理工作区" aria-label="Permalink to &quot;添加与管理工作区&quot;">​</a></h2><h3 id="添加工作区" tabindex="-1">添加工作区 <a class="header-anchor" href="#添加工作区" aria-label="Permalink to &quot;添加工作区&quot;">​</a></h3><ol><li>点击搜索框下方的**＋ 打开工作区**按钮。</li><li>在弹出的文件夹选取对话框中选择本地项目目录，点击<strong>确认</strong>。</li><li>如果该目录下有 Claude Code 历史会话，会弹出询问「<strong>同步会话</strong>」——点<strong>导入</strong>可将历史记录导入为任务；点<strong>跳过</strong>则跳过。</li></ol><p>工作区添加成功后会出现在任务列表树中。</p><h3 id="工作区操作" tabindex="-1">工作区操作 <a class="header-anchor" href="#工作区操作" aria-label="Permalink to &quot;工作区操作&quot;">​</a></h3><p>鼠标悬浮到工作区名称行，右侧出现三个快捷图标：</p><ul><li><strong>新建任务</strong>：在该工作区下新建任务</li><li><strong>查看文件</strong>：将左侧栏切换为该工作区的<strong>文件树</strong>视图（文件树顶部的<strong>返回任务</strong>按钮可退回任务列表）</li><li><strong>移除工作区</strong>：从 LoongCode 中移除该工作区条目（<strong>不影响磁盘上的实际文件</strong>）</li></ul><div class="warning custom-block"><p class="custom-block-title">移除工作区</p><p>移除工作区会删除该工作区下的所有任务记录，但磁盘上的代码与历史文件不受影响。</p></div><hr><h2 id="新建任务" tabindex="-1">新建任务 <a class="header-anchor" href="#新建任务" aria-label="Permalink to &quot;新建任务&quot;">​</a></h2><h3 id="草稿态机制" tabindex="-1">草稿态机制 <a class="header-anchor" href="#草稿态机制" aria-label="Permalink to &quot;草稿态机制&quot;">​</a></h3><p>点击**＋ 新建任务**（或按 <code>Ctrl+N</code>）后，任务进入<strong>草稿态</strong>——此时尚未写入数据库，主区域内联显示配置选择器供你挑选工作区、模型、Git 分支或 worktree（Git worktree 是 Git 的独立检出目录，允许同时在多个分支上工作）。</p><p><strong>发送第一条消息后，任务才正式创建</strong>，这样可以避免空任务堆积。</p><p>草稿会默认选中上次用过的工作区，少点一步。草稿选中的工作区被外部删除时，发送按钮会被禁用并给出提示。</p><h3 id="草稿态下可用功能" tabindex="-1">草稿态下可用功能 <a class="header-anchor" href="#草稿态下可用功能" aria-label="Permalink to &quot;草稿态下可用功能&quot;">​</a></h3><p>即使任务还在草稿态，左侧栏的文件树，右侧面板的文件标签、审查、浏览器，以及终端均可正常使用，它们按工作区工作，不依赖任务是否已落盘。</p><hr><h2 id="任务状态" tabindex="-1">任务状态 <a class="header-anchor" href="#任务状态" aria-label="Permalink to &quot;任务状态&quot;">​</a></h2><p>在默认的<strong>分组列表</strong>视图中，任务行的状态不再由单个圆点表达（v0.9.1 界面改版起），而是由三处元素共同传达：</p><ul><li><strong>左侧书签条</strong>：任务行左缘的一条细竖条，只在「选中 / 运行中 / 提问中」时出现</li><li><strong>标题明暗</strong>：未读加粗醒目、已读变灰</li><li><strong>行尾状态徽标</strong>：任务行右侧的圆环 / 圆点等小徽标</li></ul><p>任务状态仍归为五种：<strong>空闲、运行中、成功、出错、提问中</strong>。</p><h3 id="各状态的外观" tabindex="-1">各状态的外观 <a class="header-anchor" href="#各状态的外观" aria-label="Permalink to &quot;各状态的外观&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>任务行外观</th></tr></thead><tbody><tr><td><strong>空闲</strong> / <strong>成功</strong></td><td>无特殊标记的普通行——「成功」只表示刚结束的一轮没有报错，任务随即回到等待输入的「空闲」状态</td></tr><tr><td><strong>运行中</strong></td><td>左侧出现<strong>金色书签条</strong>（当前选中的任务满亮，未选中的半透明）；行尾显示<strong>橙色旋转圆环</strong>与<strong>已工作时长</strong>计时（「已工作 X秒」，每秒跳动）</td></tr><tr><td><strong>出错</strong></td><td>行尾显示<strong>红色小圆点</strong>（有未读时）；查看后变为<strong>红色空心圆环</strong></td></tr><tr><td><strong>提问中</strong></td><td>左侧书签条变为<strong>蓝色</strong>、整行带淡蓝底色，行尾显示<strong>蓝色「?」圆形徽标</strong>（脉动）——优先级最高，一眼可见</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">运行中的计时也包含后台工作（v0.9.1 起）</p><p>「运行中」的判定与计时把<strong>子智能体和后台任务</strong>也计算在内——即使主回合已经结束，只要还有后台子智能体、后台命令或<a href="/docs/features/workflows.html">动态工作流</a>（v0.9.2 起）在跑，任务行就仍显示橙色圆环并继续累计「已工作」时长（常驻服务不计入）。</p></div><blockquote><p>当前选中的任务即使处于空闲，也会显示满亮的金色书签条，用于标记「你正在看的任务」。</p></blockquote><h3 id="未读提示" tabindex="-1">未读提示 <a class="header-anchor" href="#未读提示" aria-label="Permalink to &quot;未读提示&quot;">​</a></h3><p>有没有未读消息改由<strong>标题明暗 + 金色圆点</strong>表达：</p><ul><li><strong>未读</strong>：任务标题<strong>加粗</strong>显示，行尾出现一枚<strong>金色小圆点</strong></li><li><strong>已读</strong>：切换到该任务、看过最新回复后，标题恢复灰色，金色圆点消失</li></ul><p>「运行中」不受已读影响——只要任务还在工作，橙色圆环与计时就始终可见，方便一眼看出哪些任务正在后台干活。</p><h3 id="其它徽标" tabindex="-1">其它徽标 <a class="header-anchor" href="#其它徽标" aria-label="Permalink to &quot;其它徽标&quot;">​</a></h3><p>除上述主状态徽标外，任务行右侧还可能出现：</p><table tabindex="0"><thead><tr><th>徽标</th><th>含义</th></tr></thead><tbody><tr><td><strong>⏲</strong></td><td>该任务挂有<a href="/docs/features/scheduled-send.html">定时执行</a>（可与其他徽标并存）；一次性定时刚触发且未读时显示<strong>紫色小圆点</strong></td></tr><tr><td><strong>分支标签</strong></td><td>绑定了 worktree 的任务显示其分支名小标签</td></tr><tr><td><strong>⚡N</strong></td><td>正有 N 个后台任务在运行；有后台完成未读时该徽标亮金加粗。详见<a href="/docs/features/background-tasks.html">后台任务活动</a></td></tr></tbody></table><blockquote><p>行尾主状态徽标同一时间只显示一个，优先级为：<strong>提问中 &gt; 运行中 &gt; 定时触发未读 &gt; 出错未读 &gt; 普通未读 &gt; 出错已读</strong>。</p></blockquote><div class="tip custom-block"><p class="custom-block-title">时间线视图仍是圆点</p><p><strong>时间线</strong>视图（见下文「视图模式」）的任务行保留了简洁的<strong>状态圆点</strong>：颜色对应任务状态（如运行中琥珀色、出错红色），已读后变暗淡，悬浮时圆点让位给图钉置顶按钮。</p></div><hr><h2 id="任务排序与置顶" tabindex="-1">任务排序与置顶 <a class="header-anchor" href="#任务排序与置顶" aria-label="Permalink to &quot;任务排序与置顶&quot;">​</a></h2><h3 id="按最近活动排序" tabindex="-1">按最近活动排序 <a class="header-anchor" href="#按最近活动排序" aria-label="Permalink to &quot;按最近活动排序&quot;">​</a></h3><p>任务列表与时间线分桶按<strong>最近活动时间</strong>排序——刚发过消息或刚结束一轮对话的任务会自动浮到前面（v0.4.2 起）。</p><h3 id="置顶任务" tabindex="-1">置顶任务 <a class="header-anchor" href="#置顶任务" aria-label="Permalink to &quot;置顶任务&quot;">​</a></h3><p>置顶通过任务行上的<strong>快捷按钮</strong>完成（不在右键菜单里）：</p><ol><li>将鼠标悬浮到任务行上——行首会出现一个图钉形的<strong>置顶任务</strong>按钮。</li><li>点击该按钮即完成置顶。</li></ol><p>置顶后任务出现在<strong>已置顶</strong>分组，跨视图、不受「折叠全部」影响。已置顶的任务悬浮时该按钮变为<strong>取消置顶</strong>，再点一次即可恢复。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>置顶任务受自动归档保护，不会被自动归档。</p></div><hr><h2 id="搜索任务" tabindex="-1">搜索任务 <a class="header-anchor" href="#搜索任务" aria-label="Permalink to &quot;搜索任务&quot;">​</a></h2><p>搜索框（占位提示「搜索任务…」）位于侧栏顶部 Logo 区域下方，输入关键词后任务列表实时筛选。</p><ul><li>无匹配时显示「未找到匹配任务」</li><li>点击搜索框右侧的<strong>清除搜索</strong>按钮可清空关键词</li></ul><hr><h2 id="归档任务" tabindex="-1">归档任务 <a class="header-anchor" href="#归档任务" aria-label="Permalink to &quot;归档任务&quot;">​</a></h2><h3 id="手动归档" tabindex="-1">手动归档 <a class="header-anchor" href="#手动归档" aria-label="Permalink to &quot;手动归档&quot;">​</a></h3><p>右键点击任务行，选择<strong>归档</strong>即可（任务行悬浮时行尾的<strong>任务操作</strong>下拉菜单中同样可以归档）。</p><p>归档后任务从主列表移出，进入归档视图，主列表更加清爽。</p><p>取消归档：进入归档视图后，右键任务选<strong>取消归档</strong>，任务的活动时间会被重置，回到主列表最上方，方便立即继续。</p><h3 id="自动归档" tabindex="-1">自动归档 <a class="header-anchor" href="#自动归档" aria-label="Permalink to &quot;自动归档&quot;">​</a></h3><p>应用<strong>启动时</strong>与<strong>每小时</strong>各跑一次自动归档，按「最近活动时间」超过阈值自动将久未触碰的任务归档（v0.4.3 起）。</p><p><strong>保护规则</strong>：运行中任务和已置顶任务不会被自动归档。</p><p><strong>调整阈值</strong>：在<strong>设置 → 常规</strong>中可开关自动归档，并设置阈值数值与单位（小时 / 天 / 月），默认开启、7 天。</p><h3 id="查看归档视图" tabindex="-1">查看归档视图 <a class="header-anchor" href="#查看归档视图" aria-label="Permalink to &quot;查看归档视图&quot;">​</a></h3><ol><li>在任务大组头右侧点击<strong>查看归档</strong>。</li><li>进入归档视图后，任务按归档时间降序排列。</li><li>归档视图下自动隐藏置顶区和新建入口，没有归档任务时显示「暂无归档任务」。</li><li>点击<strong>退出归档</strong>返回主任务列表。</li></ol><p><img src="'+r+'" alt="截图：归档视图已打开，任务按归档时间降序排列，右上角有「退出归档」按钮"></p><hr><h2 id="任务右键菜单" tabindex="-1">任务右键菜单 <a class="header-anchor" href="#任务右键菜单" aria-label="Permalink to &quot;任务右键菜单&quot;">​</a></h2><p>右键任务行可弹出操作菜单，仅包含以下三类操作：</p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>重命名</strong></td><td>仅未归档任务显示</td></tr><tr><td><strong>归档</strong> / <strong>取消归档</strong></td><td>按任务当前归档状态二选一</td></tr><tr><td><strong>删除</strong></td><td>危险操作，需二次确认</td></tr></tbody></table><p>置顶不在右键菜单中——它是任务行悬浮时行首出现的图钉快捷按钮，见上文「置顶任务」。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>任务行悬浮时行尾还会出现<strong>任务操作</strong>下拉菜单，它提供与右键菜单相同的操作。</p></div><div class="danger custom-block"><p class="custom-block-title">删除任务</p><p>删除操作不可恢复，请确认后再继续。删除任务仅删除 LoongCode 内的对话记录，不影响磁盘上的项目代码。</p></div><hr><h2 id="视图模式" tabindex="-1">视图模式 <a class="header-anchor" href="#视图模式" aria-label="Permalink to &quot;视图模式&quot;">​</a></h2><p>任务大组头提供两种视图切换：</p><ul><li><strong>分组列表</strong>：按工作区分组展示，可展开 / 折叠各工作区</li><li><strong>时间线</strong>：按时间桶（今天、昨天、本周……）排列，跨工作区浏览</li></ul><div class="tip custom-block"><p class="custom-block-title">选中任务自动定位（v0.8.0 起）</p><p>无论当前处于哪种视图，当你（在分屏中切换分栏、或通过机器人 / 移动端等方式）选中一个任务时，左侧栏会<strong>自动展开并滚动定位到它所在的分组</strong>——已置顶任务定位到「已置顶」组，其余按当前视图定位到对应的工作区分组或时间线日期桶，省去手动翻找折叠分组的麻烦。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解任务管理之后，你可以进一步探索如何将多个任务并排显示，前往<a href="/docs/features/multi-pane.html">多任务分屏</a>了解分屏功能。</p>',85)])])}const b=o(e,[["render",l]]);export{u as __pageData,b as default};
